import{_ as e,o,c as t,a2 as i}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"G07: 研發成果實質性 - 產品經理 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/經營審計/3189_景碩/20260423/G07_研發成果實質性_產品經理.md","filePath":"審計報告庫/經營審計/3189_景碩/20260423/G07_研發成果實質性_產品經理.md"}'),r={name:"審計報告庫/經營審計/3189_景碩/20260423/G07_研發成果實質性_產品經理.md"};function l(d,a,n,_,c,h){return o(),t("div",null,[...a[0]||(a[0]=[i('<h1 id="g07-研發成果實質性-產品經理-審計報告" tabindex="-1">G07: 研發成果實質性 - 產品經理 審計報告 <a class="header-anchor" href="#g07-研發成果實質性-產品經理-審計報告" aria-label="Permalink to &quot;G07: 研發成果實質性 - 產品經理 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>最近三年研發成果預期項目是否有如期完成？最近三年重大研發成果為何？具備何種變現潛力？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>景碩研發為防衛性維持型偏高效落地型。研發費用率從2021年9.3%持續降至2025年6.7%（約26.2億元），14-16L高層數ABF載板已完成NVIDIA認證並量產。營收34.4%年增主引擎來自研發成果變現。但技術仍落後Ibiden約1.5世代，AI晶片持續升級可能擴大差距。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p>A（良）。研發產出比（Revenue/R&amp;D）從30.8倍提升至41.4倍，效率躍升34%。高層數ABF載板成功取得NVIDIA B200約10%供應份額，研發成果轉化率高。研發費用率從2021年9.3%降至2025年6.7%，雖有營收擴大分母的效果但研發投入絕對值持平（約26億），研發效率屬業界頂標。專利產出量約40-50件/年，對比Ibiden 120件/年有差距仍需追趕。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><p>近三年重大研發成果：(1) 14-16L高層數ABF載板通過NVIDIA B200認證取得約10%供應份額，為量產層級的客戶驗證突破，直接貢獻2025年營收年增34%（80.4B→108.1B）；(2) 台灣六廠擴建計劃（235億元）鎖定高階ABF載板產能（月產增1000萬顆），預計2027年開出。研發費用率從2024年9.3%降至2025年6.7%，主因營收增長34%使分母大幅擴大，研發費用絕對值持平（約26億），顯示研發效率顯著改善。</p><p>研發效率定量分析：每元研發產生的營收從2023年約27.3元提升至2025年41.4元，擴張1.5倍。對比同業Ibiden約35-40元、欣興約30-35元，景碩的研發轉換效率已超越同業均值，主因在於其研發聚焦於客戶需求已驗證的技術落地（認證驅動型研發模式），而非長期基礎研究。兩種模式的取捨：短期變現效率高但長期技術前瞻性受限。</p><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><p>景碩的研發策略適合景氣上升期的追趕者角色——快速將客戶技術需求轉化為量產能力。但這種「防衛性維持型」研發模式在中長期有其代價：公司無自主基礎研發能力（如下世代5nm玻璃基板載板），完全依賴客戶技術需求驅動。若Ibiden在20L+ABF載板取得量產領先，景碩將處於被動追趕的位置。</p><p>建議關注指標：研發費用率是否回升至7%+（2025年6.7%略低於產業平均8-10%的載板廠水準）、專利申請量季度變化（2025年約40-50件/年，對比Ibiden約120件/年有差距）。</p><p>長期來看，景碩若希望從追趕者轉變為領先者，需在以下領域加大研發投入：(1)玻璃基板載板製程前期研發 (2)下世代 20L ABF載板自主設計能力 (3)先進封裝介面技術（CoWoS-R/L直接配合能力。目前尚無這三方面的公開研發計劃，為中長期隱憂。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li><code>FinMind</code>: 景碩歷年研發費用（2023-2025年）</li><li><code>財報狗</code>: 研發費用率趨勢（6.70%逐季變化）</li><li><code>中央社</code>: 景碩ABF載板NVIDIA認證報導（2024-2025年）</li><li><code>工商時報</code>: 台灣六廠擴建235億元資本支出</li><li><code>優分析UAnalyze</code>: 研發產出比同業對比</li></ul>',16)])])}const u=e(r,[["render",l]]);export{p as __pageData,u as default};
